from __future__ import annotations

from dataclasses import dataclass
from random import Random
from typing import Final
from collections import deque

WALL: Final[str] = "#"
FLOOR: Final[str] = "."
PLAYER: Final[str] = "@"
MONSTER: Final[str] = "g"

@dataclass(frozen=True)
class Point:
    x: int
    y: int

@dataclass
class Fighter:
    hp: int
    power: int
    armor: int = 0

    @property
    def alive(self) -> bool:
        return self.hp > 0

@dataclass
class Entity:
    name: str
    pos: Point
    fighter: Fighter | None = None

@dataclass
class GameMap:
    width: int
    height: int
    tiles: list[list[str]]

    @classmethod
    def filled(cls, width: int, height: int, tile: str) -> GameMap:
        return cls(width, height, [[tile for _ in range(width)] for _ in range(height)])

    def in_bounds(self, point: Point) -> bool:
        return 0 <= point.x < self.width and 0 <= point.y < self.height

    def is_walkable(self, point: Point) -> bool:
        return self.in_bounds(point) and self.tiles[point.y][point.x] == FLOOR

    def count_floor_neighbors(self, point: Point) -> int:
        count = 0
        for dy in (-1, 0, 1):
            for dx in (-1, 0, 1):
                if dx == 0 and dy == 0:
                    continue
                neighbor = Point(point.x + dx, point.y + dy)
                if self.in_bounds(neighbor) and self.tiles[neighbor.y][neighbor.x] == FLOOR:
                    count += 1
        return count

    def set_tile(self, point: Point, tile: str) -> None:
        if self.in_bounds(point):
            self.tiles[point.y][point.x] = tile

def generate_cellular_automata(
    width: int, height: int, seed: int, fill_threshold: float = 0.45,
    iterations: int = 4, birth_threshold: int = 5, survival_threshold: int = 4,
) -> GameMap:
    rng = Random(seed)
    game_map = GameMap.filled(width, height, WALL)

    for y in range(height):
        for x in range(width):
            if rng.random() < fill_threshold:
                game_map.tiles[y][x] = FLOOR

    for _ in range(iterations):
        new_tiles = [[WALL for _ in range(width)] for _ in range(height)]
        for y in range(height):
            for x in range(width):
                point = Point(x, y)
                floor_neighbors = game_map.count_floor_neighbors(point)

                if game_map.tiles[y][x] == FLOOR:
                    if floor_neighbors >= survival_threshold:
                        new_tiles[y][x] = FLOOR
                else:
                    if floor_neighbors >= birth_threshold:
                        new_tiles[y][x] = FLOOR
        game_map.tiles = new_tiles

    return game_map

def find_connected_components(game_map: GameMap) -> list[set[Point]]:
    visited: set[Point] = set()
    components: list[set[Point]] = []

    for y in range(game_map.height):
        for x in range(game_map.width):
            point = Point(x, y)
            if (game_map.tiles[y][x] == FLOOR and point not in visited):

                component: set[Point] = set()
                queue: deque[Point] = deque([point])

                while queue:
                    current = queue.popleft()
                    if current in visited:
                        continue
                    visited.add(current)
                    component.add(current)

                    for dy in (-1, 0, 1):
                        for dx in (-1, 0, 1):
                            if dx == 0 and dy == 0:
                                continue
                            neighbor = Point(current.x + dx, current.y + dy)
                            if (game_map.in_bounds(neighbor) and 
                                game_map.tiles[neighbor.y][neighbor.x] == FLOOR and 
                                neighbor not in visited):
                                queue.append(neighbor)

                components.append(component)

    return components

def repair_connectivity(game_map: GameMap, seed: int) -> None:
    components = find_connected_components(game_map)

    if len(components) <= 1:
        return

    components.sort(key=len, reverse=True)
    main_component = components[0]

    for other_component in components[1:]:
        min_distance = float('inf')
        closest_pair: tuple[Point, Point] | None = None

        for p1 in main_component:
            for p2 in other_component:
                distance = abs(p1.x - p2.x) + abs(p1.y - p2.y)
                if distance < min_distance:
                    min_distance = distance
                    closest_pair = (p1, p2)

        if closest_pair:
            p1, p2 = closest_pair

            if p1.x != p2.x:
                start_x, end_x = min(p1.x, p2.x), max(p1.x, p2.x)
                for x in range(start_x, end_x + 1):
                    game_map.set_tile(Point(x, p1.y), FLOOR)

            if p1.y != p2.y:
                start_y, end_y = min(p1.y, p2.y), max(p1.y, p2.y)
                for y in range(start_y, end_y + 1):
                    game_map.set_tile(Point(p2.x, y), FLOOR)

            main_component.update(other_component)

@dataclass
class Game:
    game_map: GameMap
    player: Entity
    monsters: list[Entity]
    log: list[str]

    def entity_at(self, point: Point) -> Entity | None:
        for monster in self.monsters:
            if monster.pos == point and monster.fighter is not None and monster.fighter.alive:
                return monster
        return None

    def move_player(self, dx: int, dy: int) -> None:
        destination = Point(self.player.pos.x + dx, self.player.pos.y + dy)
        target = self.entity_at(destination)
        if target is not None:
            self.attack(self.player, target)
        elif self.game_map.is_walkable(destination):
            self.player.pos = destination

    def attack(self, attacker: Entity, defender: Entity) -> None:
        if attacker.fighter is None or defender.fighter is None:
            return
        damage = max(0, attacker.fighter.power - defender.fighter.armor)
        defender.fighter.hp -= damage
        self.log.append(f"{attacker.name} hits {defender.name} for {damage} damage")
        if defender.fighter.hp <= 0:
            self.log.append(f"{defender.name} dies")

def new_game(width: int = 40, height: int = 24, seed: int = 1, fill_threshold: float = 0.45) -> Game:
    game_map = generate_cellular_automata(width, height, seed, fill_threshold)
    repair_connectivity(game_map, seed)

    floor_tiles = []
    for y in range(game_map.height):
        for x in range(game_map.width):
            if game_map.tiles[y][x] == FLOOR:
                floor_tiles.append(Point(x, y))

    if not floor_tiles:
        raise RuntimeError("No floor tiles generated")

    player = Entity("player", floor_tiles[0], Fighter(hp=30, power=8, armor=2))

    rng = Random(seed + 2000)
    monsters = []
    available_tiles = floor_tiles[1:min(11, len(floor_tiles))]
    rng.shuffle(available_tiles)

    for i, pos in enumerate(available_tiles[:5]):
        monster_type = ["goblin", "orc", "skeleton", "troll", "zombie"][i % 5]
        monsters.append(Entity(monster_type, pos, Fighter(hp=10 + i * 2, power=4 + i, armor=i)))

    return Game(game_map, player, monsters, [])

def run_headless(seed: int, turns: int) -> Game:
    game = new_game(seed=seed)
    rng = Random(seed + 3000)
    moves = [Point(1, 0), Point(0, 1), Point(-1, 0), Point(0, -1)]
    for _ in range(turns):
        move = rng.choice(moves)
        game.move_player(move.x, move.y)
    return game

if __name__ == "__main__":
    run_headless(seed=123, turns=200)
